<?php
if(!defined("IN_ESOTALK"))exit;class profile extends Controller{var $view="profile.view.php";var $member=array();var $sections=array();function init(){if(defined("AJAX_REQUEST"))return;if(!empty($_GET["q2"]))$memberId=(int)$_GET["q2"];elseif($this->esoTalk->user)$memberId=$this->esoTalk->user["memberId"];else $memberId=false;if(!$memberId or !($this->member=$this->getMember($memberId))){$this->esoTalk->message("memberDoesntExist",false);redirect("");}global $language;$this->title=sprintf($language["profile"],$this->member["name"]);$this->callHook("init");}function ajax(){if($return=$this->callHook("ajax",null,true))return $return;}function addSection($sectionHTML,$position=false){addToArray($this->sections,$sectionHTML,$position);}function getMember($memberId){global $config;if(empty($memberId))return false;$select=array("m.memberId AS memberId","m.name AS name","IF(m.color>{$this->esoTalk->skin->numberOfColors},{$this->esoTalk->skin->numberOfColors},m.color) AS color","m.account AS account","m.lastSeen AS lastSeen","IF(".(time()-$config["userOnlineExpire"])."<m.lastSeen,m.lastAction,'') AS lastAction","m.avatarFormat AS avatarFormat","(SELECT MIN(time) FROM {$config["tablePrefix"]}posts p WHERE p.memberId=m.memberId) AS firstPosted","(SELECT COUNT(*) FROM {$config["tablePrefix"]}conversations c WHERE c.startMember=m.memberId) AS conversationsStarted","(SELECT COUNT(DISTINCT conversationId) FROM {$config["tablePrefix"]}posts p WHERE p.memberId=m.memberId) AS conversationsParticipated","(SELECT COUNT(*) FROM {$config["tablePrefix"]}posts p WHERE p.memberId=m.memberId) AS postCount");$from=array("{$config["tablePrefix"]}members m");$where=array("m.memberId=$memberId");$components=array("select"=>$select,"from"=>$from,"where"=>$where);$this->callHook("beforeGetMember",array(&$components));$query=$this->esoTalk->db->constructSelectQuery($components);$result=$this->esoTalk->db->query($query);if(!$this->esoTalk->db->numRows($result))return false;$member=$this->esoTalk->db->fetchAssoc($result);$this->callHook("afterGetMember",array(&$member));return $member;}}?>
